// DependencyTracker gains a selector registry
recordAccess(itemId, selector = null) {
    // ... existing tracking code ...
    if (selector) this.selectors.set(ctxId + ':' + itemId, selector);
}

// Reactive subscription checks selectors before scheduling
this.kernel.events.on(EVENT_IDS.ITEM_UPDATED, (event) => {
    const { id, previous, current } = event.content;
    const dependents = this._depTracker.getDependents(id);
    for (const ctxId of dependents) {
        const selector = this._depTracker.selectors.get(ctxId + ':' + id);
        if (selector) {
            if (deepEqual(selector(previous), selector(current))) continue;
        }
        this._pendingReRenders.add(ctxId);
    }
});
